exercises.solution_code:
#include <iostream>
#include <string>
#include <string_view>

constexpr std::string_view PREFIX_HELLO = "Hello, ";
constexpr std::string_view PREFIX_HI    = "Hi, ";

std::string_view extractBody(std::string_view line, std::string_view prefix)
{
    line.remove_prefix(prefix.size());
    return line;
}

int main()
{
    std::string line{};
    std::getline(std::cin, line);

    std::string_view sv{line};

    if (sv.starts_with(PREFIX_HELLO))
        std::cout << "Greeting -- body: " << extractBody(sv, PREFIX_HELLO) << '\n';
    else if (sv.starts_with(PREFIX_HI))
        std::cout << "Greeting -- body: " << extractBody(sv, PREFIX_HI) << '\n';
    else
        std::cout << "Not a greeting: " << sv << '\n';

    return 0;
}
